namespace RecipeCommunity.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public List<int> Ratings { get; set; } = new();

    public double AverageRating => Ratings.Count > 0 ? Ratings.Average() : 0;
}

using RecipeCommunity.Models;

namespace RecipeCommunity.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe
        {
            Id = 1,
            Title = "Classic Margherita Pizza",
            Category = "Italian",
            Ingredients = "Pizza dough\nSan Marzano tomatoes\nFresh mozzarella\nFresh basil\nOlive oil\nSalt",
            Steps = "1. Preheat oven to 475°F (245°C).\n2. Roll out dough on a floured surface.\n3. Spread crushed tomatoes evenly.\n4. Tear mozzarella and distribute over sauce.\n5. Bake for 10-12 minutes until crust is golden.\n6. Top with fresh basil and a drizzle of olive oil.",
            Ratings = new List<int> { 5, 4, 5, 4 }
        },
        new Recipe
        {
            Id = 2,
            Title = "Spaghetti Carbonara",
            Category = "Italian",
            Ingredients = "Spaghetti\nGuanciale or pancetta\nEggs\nPecorino Romano\nBlack pepper",
            Steps = "1. Cook pasta in salted boiling water.\n2. Crisp guanciale in a pan.\n3. Whisk eggs with grated pecorino and pepper.\n4. Toss hot pasta with guanciale.\n5. Remove from heat and stir in egg mixture.\n6. Serve immediately with extra cheese.",
            Ratings = new List<int> { 5, 5, 4 }
        },
        new Recipe
        {
            Id = 3,
            Title = "Chicken Tikka Masala",
            Category = "Indian",
            Ingredients = "Chicken thighs\nYogurt\nGaram masala\nTurmeric\nCumin\nCanned tomatoes\nHeavy cream\nGarlic\nGinger\nOnion",
            Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or broil chicken until charred.\n3. Sauté onion, garlic, and ginger.\n4. Add tomatoes and simmer 15 minutes.\n5. Stir in cream and cooked chicken.\n6. Simmer 10 minutes and serve with rice.",
            Ratings = new List<int> { 5, 4, 5 }
        },
        new Recipe
        {
            Id = 4,
            Title = "Vegetable Pad Thai",
            Category = "Thai",
            Ingredients = "Rice noodles\nTofu\nBean sprouts\nPeanuts\nLime\nTamarind paste\nFish sauce\nSugar\nGarlic\nEggs",
            Steps = "1. Soak rice noodles in warm water 20 minutes.\n2. Make sauce: mix tamarind, fish sauce, and sugar.\n3. Stir-fry tofu until golden.\n4. Scramble eggs in the pan.\n5. Add noodles and sauce, toss well.\n6. Top with bean sprouts, peanuts, and lime.",
            Ratings = new List<int> { 4, 4, 3, 5 }
        },
        new Recipe
        {
            Id = 5,
            Title = "Beef Tacos",
            Category = "Mexican",
            Ingredients = "Ground beef\nTaco seasoning\nCorn tortillas\nLettuce\nTomato\nCheddar cheese\nSour cream\nSalsa",
            Steps = "1. Brown ground beef in a skillet.\n2. Add taco seasoning and water, simmer 5 minutes.\n3. Warm tortillas in a dry pan.\n4. Fill tortillas with seasoned beef.\n5. Top with lettuce, tomato, cheese, sour cream, and salsa.",
            Ratings = new List<int> { 4, 5, 4 }
        },
        new Recipe
        {
            Id = 6,
            Title = "Chocolate Lava Cake",
            Category = "Desserts",
            Ingredients = "Dark chocolate\nButter\nEggs\nSugar\nFlour\nVanilla extract",
            Steps = "1. Preheat oven to 425°F (220°C).\n2. Melt chocolate and butter together.\n3. Whisk eggs, sugar, and vanilla.\n4. Fold chocolate mixture into eggs.\n5. Add flour and mix gently.\n6. Pour into greased ramekins.\n7. Bake 12-14 minutes until edges are firm but center is soft.",
            Ratings = new List<int> { 5, 5, 5, 4, 5 }
        }
    };

    private int _nextId = 7;

    public List<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public List<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) =>
        _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe != null && stars >= 1 && stars <= 5)
        {
            recipe.Ratings.Add(stars);
        }
    }

    public void AddRecipe(string title, string category, string ingredients, string steps)
    {
        _recipes.Add(new Recipe
        {
            Id = _nextId++,
            Title = title,
            Category = category,
            Ingredients = ingredients,
            Steps = steps
        });
    }
}

