arguments.file_text:
@page "/"
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>Recipe Community</PageTitle>

<div class="container">
    <div class="text-center my-5">
        <h1 class="display-4">🍳 Recipe Community</h1>
        <p class="lead text-muted">Discover and share delicious recipes from around the world</p>
    </div>

    <h2 class="mb-4">Browse by Category</h2>
    <div class="row g-4">
        @foreach (var category in RecipeService.GetCategories())
        {
            <div class="col-md-4 col-sm-6">
                <a href="/recipes/@category.ToLower()" class="text-decoration-none">
                    <div class="card h-100 shadow-sm border-0">
                        <div class="card-body text-center p-4">
                            <h3 class="card-title">@GetCategoryEmoji(category) @category</h3>
                            <p class="text-muted">@RecipeService.GetByCategory(category).Count recipes</p>
                        </div>
                    </div>
                </a>
            </div>
        }
    </div>

    <div class="text-center mt-5">
        <a href="/submit" class="btn btn-success btn-lg">📝 Submit Your Recipe</a>
    </div>
</div>

@code {
    private string GetCategoryEmoji(string category) => category switch
    {
        "Italian" => "🇮🇹",
        "Indian" => "🇮🇳",
        "Thai" => "🇹🇭",
        "Mexican" => "🇲🇽",
        "Desserts" => "🍰",
        _ => "🍽️"
    };
}

@page "/recipes/{Category}"
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>@Category Recipes - Recipe Community</PageTitle>

<div class="container">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">@Category</li>
        </ol>
    </nav>

    <h1 class="mb-4">@Category Recipes</h1>

    @if (Recipes.Any())
    {
        <div class="row g-4">
            @foreach (var recipe in Recipes)
            {
                <div class="col-md-6">
                    <div class="card h-100 shadow-sm">
                        <div class="card-body">
                            <h4 class="card-title">
                                <a href="/recipe/@recipe.Id" class="text-decoration-none">@recipe.Title</a>
                            </h4>
                            <p class="text-muted mb-1">
                                @if (recipe.Ratings.Count > 0)
                                {
                                    <span>⭐ @recipe.AverageRating.ToString("F1") (@recipe.Ratings.Count ratings)</span>
                                }
                                else
                                {
                                    <span>No ratings yet</span>
                                }
                            </p>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
    else
    {
        <div class="alert alert-info">No recipes found in this category.</div>
    }
</div>

@code {
    [Parameter]
    public string Category { get; set; } = string.Empty;

    private List<RecipeCommunity.Models.Recipe> Recipes { get; set; } = new();

    protected override void OnParametersSet()
    {
        Recipes = RecipeService.GetByCategory(Category);
    }
}

@page "/recipe/{Id:int}"
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<PageTitle>@(Recipe?.Title ?? "Recipe") - Recipe Community</PageTitle>

<div class="container">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            @if (Recipe != null)
            {
                <li class="breadcrumb-item"><a href="/recipes/@Recipe.Category.ToLower()">@Recipe.Category</a></li>
                <li class="breadcrumb-item active">@Recipe.Title</li>
            }
        </ol>
    </nav>

    @if (Recipe != null)
    {
        <h1 class="mb-2">@Recipe.Title</h1>
        <p class="text-muted">
            Category: <a href="/recipes/@Recipe.Category.ToLower()">@Recipe.Category</a>
            @if (Recipe.Ratings.Count > 0)
            {
                <span class="ms-3">⭐ @Recipe.AverageRating.ToString("F1") (@Recipe.Ratings.Count ratings)</span>
            }
        </p>

        <div class="row mt-4">
            <div class="col-md-4">
                <div class="card mb-4">
                    <div class="card-header"><h5 class="mb-0">🧾 Ingredients</h5></div>
                    <div class="card-body">
                        <ul class="list-unstyled mb-0">
                            @foreach (var ingredient in Recipe.Ingredients.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                            {
                                <li class="mb-1">• @ingredient</li>
                            }
                        </ul>
                    </div>
                </div>
            </div>
            <div class="col-md-8">
                <div class="card mb-4">
                    <div class="card-header"><h5 class="mb-0">👨‍🍳 Instructions</h5></div>
                    <div class="card-body">
                        @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
                        {
                            <p>@step</p>
                        }
                    </div>
                </div>
            </div>
        </div>

        <div class="card mt-3">
            <div class="card-body">
                <h5>Rate this Recipe</h5>
                <RecipeCommunity.Components.Shared.StarRating RecipeId="Recipe.Id" />
            </div>
        </div>
    }
    else
    {
        <div class="alert alert-warning">Recipe not found.</div>
    }
</div>

@code {
    [Parameter]
    public int Id { get; set; }

    private RecipeCommunity.Models.Recipe? Recipe { get; set; }

    protected override void OnParametersSet()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@using RecipeCommunity.Services
@inject RecipeService RecipeService

<div class="d-inline-block">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="fs-3" style="cursor: pointer;" @onclick="() => Rate(star)">
            @(star <= _selectedRating ? "★" : "☆")
        </span>
    }

    @if (_submitted)
    {
        <span class="ms-2 text-success">Thanks for rating!</span>
    }
    else
    {
        <span class="ms-2 text-muted">Click a star to rate</span>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int _selectedRating = 0;
    private bool _submitted = false;

    private void Rate(int stars)
    {
        _selectedRating = stars;
        _submitted = true;
        RecipeService.AddRating(RecipeId, stars);
    }
}

@page "/submit"
@rendermode InteractiveServer
@using RecipeCommunity.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - Recipe Community</PageTitle>

<div class="container">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">Submit Recipe</li>
        </ol>
    </nav>

    <h1 class="mb-4">📝 Submit Your Recipe</h1>

    @if (_submitted)
    {
        <div class="alert alert-success">
            <h4>Recipe submitted successfully!</h4>
            <p>Your recipe "<strong>@_title</strong>" has been added to the community.</p>
            <a href="/" class="btn btn-primary">Back to Home</a>
        </div>
    }
    else
    {
        <div class="card shadow-sm">
            <div class="card-body">
                <EditForm Model="this" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
                    <div class="mb-3">
                        <label for="title" class="form-label">Recipe Title</label>
                        <InputText id="title" @bind-Value="_title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
                    </div>

                    <div class="mb-3">
                        <label for="category" class="form-label">Category</label>
                        <InputSelect id="category" @bind-Value="_category" class="form-select">
                            <option value="">-- Select a category --</option>
                            @foreach (var cat in RecipeService.GetCategories())
                            {
                                <option value="@cat">@cat</option>
                            }
                            <option value="Other">Other</option>
                        </InputSelect>
                    </div>

                    <div class="mb-3">
                        <label for="ingredients" class="form-label">Ingredients (one per line)</label>
                        <InputTextArea id="ingredients" @bind-Value="_ingredients" class="form-control" rows="6" placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs..." />
                    </div>

                    <div class="mb-3">
                        <label for="steps" class="form-label">Steps (one per line)</label>
                        <InputTextArea id="steps" @bind-Value="_steps" class="form-control" rows="6" placeholder="1. Preheat oven to 350°F&#10;2. Mix dry ingredients..." />
                    </div>

                    <button type="submit" class="btn btn-success btn-lg" disabled="@(!IsValid)">Submit Recipe</button>
                </EditForm>
            </div>
        </div>
    }
</div>

@code {
    private string _title = string.Empty;
    private string _category = string.Empty;
    private string _ingredients = string.Empty;
    private string _steps = string.Empty;
    private bool _submitted = false;

    private bool IsValid => !string.IsNullOrWhiteSpace(_title) &&
                            !string.IsNullOrWhiteSpace(_category) &&
                            !string.IsNullOrWhiteSpace(_ingredients) &&
                            !string.IsNullOrWhiteSpace(_steps);

    private void HandleSubmit()
    {
        if (IsValid)
        {
            RecipeService.AddRecipe(_title, _category, _ingredients, _steps);
            _submitted = true;
        }
    }
}

