+    }
+
+    @if (_submitted)
+    {
+        <span class="ms-2 text-success">Thanks for rating!</span>
+    }
+    else
+    {
+        <span class="ms-2 text-muted">Click a star to rate</span>
+    }
+</div>
+
+@code {
+    [Parameter]
+    public int RecipeId { get; set; }
+
+    private int _selectedRating = 0;
+    private bool _submitted = false;
+
+    private void Rate(int stars)
+    {
+        _selectedRating = stars;
+        _submitted = true;
+        RecipeService.AddRating(RecipeId, stars);
+    }
+}
+

