@page "/submit"
@rendermode InteractiveServer
@using RecipeCommunity.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - Recipe Community</PageTitle>

<div class="container">
    <nav aria-label="breadcrumb">
        <ol class="breadcrumb">
            <li class="breadcrumb-item"><a href="/">Home</a></li>
            <li class="breadcrumb-item active">Submit Recipe</li>
        </ol>
    </nav>

    <h1 class="mb-4">📝 Submit Your Recipe</h1>

    @if (_submitted)
    {
        <div class="alert alert-success">
            <h4>Recipe submitted successfully!</h4>
            <p>Your recipe "<strong>@_title</strong>" has been added to the community.</p>
            <a href="/" class="btn btn-primary">Back to Home</a>
        </div>
    }
    else
    {
        <div class="card shadow-sm">
            <div class="card-body">
                <EditForm Model="this" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
                    <div class="mb-3">
                        <label for="title" class="form-label">Recipe Title</label>
                        <InputText id="title" @bind-Value="_title" class="form-control" placeholder="e.g., Grandma's Apple Pie" />
                    </div>

                    <div class="mb-3">
                        <label for="category" class="form-label">Category</label>
                        <InputSelect id="category" @bind-Value="_category" class="form-select">
                            <option value="">-- Select a category --</option>
                            @foreach (var cat in RecipeService.GetCategories())
                            {
                                <option value="@cat">@cat</option>
                            }
                            <option value="Other">Other</option>
                        </InputSelect>
                    </div>

                    <div class="mb-3">
                        <label for="ingredients" class="form-label">Ingredients (one per line)</label>
                        <InputTextArea id="ingredients" @bind-Value="_ingredients" class="form-control" rows="6" placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs..." />
                    </div>

                    <div class="mb-3">
                        <label for="steps" class="form-label">Steps (one per line)</label>
                        <InputTextArea id="steps" @bind-Value="_steps" class="form-control" rows="6" placeholder="1. Preheat oven to 350°F&#10;2. Mix dry ingredients..." />
                    </div>

                    <button type="submit" class="btn btn-success btn-lg" disabled="@(!IsValid)">Submit Recipe</button>
                </EditForm>
            </div>
        </div>
    }
</div>

@code {
    private string _title = string.Empty;
    private string _category = string.Empty;
    private string _ingredients = string.Empty;
    private string _steps = string.Empty;
    private bool _submitted = false;

    private bool IsValid => !string.IsNullOrWhiteSpace(_title) &&
                            !string.IsNullOrWhiteSpace(_category) &&
                            !string.IsNullOrWhiteSpace(_ingredients) &&
                            !string.IsNullOrWhiteSpace(_steps);

    private void HandleSubmit()
    {
        if (IsValid)
        {
            RecipeService.AddRecipe(_title, _category, _ingredients, _steps);
            _submitted = true;
        }
    }
}

